export const specialty = specialties[0];
export const censo = specialty.censo;

export function getSpecialty(specialtyId) {
  return specialties.find((item) => item.id === specialtyId) || specialty;
}

export function normalizeChapa(chapa) {
  const digits = String(chapa || "").replace(/\D/g, "");
  if (!digits) return "";
  if (digits.length >= 5) return digits.slice(-5);
  return formatConductorChapa(digits);
}

export function formatChapa(chapa) {
  return normalizeChapa(chapa);
}

export function normalizeDoor(rawDoor) {
  return normalizeChapa(rawDoor);
}

export function findByChapa(chapa, specialtyId = specialty.id) {
  const activeSpecialty = getSpecialty(specialtyId);
  const normalized = normalizeChapa(chapa);
  if (!normalized) return null;
  return activeSpecialty.censo.find((item) => item.chapa === normalized) || null;
}

export function distanceForward(fromPosition, toPosition, size) {
  if (!fromPosition || !toPosition) return null;
  if (toPosition >= fromPosition) return toPosition - fromPosition;
  return size - fromPosition + toPosition;
}

export function getDoorState(userChapa, doors, specialtyId = specialty.id) {
  const activeSpecialty = getSpecialty(specialtyId);
  const activeDoors = Array.isArray(doors) ? doors : activeSpecialty.doors;
  const user = findByChapa(userChapa, activeSpecialty.id);

  return DOOR_ORDER.map((key) => activeDoors.find((door) => door.key === key)).filter(Boolean).map((door) => {
    const doorChapa = normalizeDoor(door.raw);
    const doorWorker = findByChapa(doorChapa, activeSpecialty.id);
    const distance = user && doorWorker
      ? distanceForward(doorWorker.position, user.position, activeSpecialty.censo.length)
      : null;

    return {
      ...door,
      doorChapa,
      doorPosition: doorWorker?.position || null,
      userPosition: user?.position || null,
      distance
    };
  });
}

export function classifyDistance(distance) {
  if (distance === null) return "muted";
  if (distance === 0) return "now";
  if (distance <= 20) return "near";
  if (distance <= 80) return "medium";
  return "far";
}

export function validateCenso() {
  return validateSpecialtyCenso(specialty.id);
}

export function validateSpecialtyCenso(specialtyId) {
  const activeSpecialty = getSpecialty(specialtyId);
  const seen = new Set();
  const duplicates = [];
  for (const item of activeSpecialty.censo) {
    if (seen.has(item.chapa)) duplicates.push(item.chapa);
    seen.add(item.chapa);
  }

  return {
    count: activeSpecialty.censo.length,
    expected: activeSpecialty.expectedSize,
    ok: activeSpecialty.censo.length === activeSpecialty.expectedSize && duplicates.length === 0,
    duplicates
  };
}
